        switch event.phase {
        case .request:
            AnalyticsDebug.shared.log(.verbose, "API: request", metadata: meta, file: file, function: function, line: line)
        case .response:
            AnalyticsDebug.shared.log(.info, "API: response", metadata: meta, file: file, function: function, line: line)
        case .failure:
            if let error = event.error {
                AnalyticsDebug.shared.logError(error, context: "API: failure", metadata: meta, file: file, function: function, line: line)
            } else {
