        let slice = data.count > maxBytes ? data.prefix(maxBytes) : data[0..<data.count]
        if let s = String(data: slice, encoding: .utf8) {
            return data.count > maxBytes ? (s + "…(truncated)") : s
        }
        return "Data(\(data.count) bytes)"
    }

    private func sanitizeHeaders(_ headers: [String: String]) -> [String: String] {
        var out = headers
        if !AnalyticsDebug.shared.config.includeTokens {
            for key in out.keys {
