public final class NetworkDebugURLProtocol: URLProtocol {
    private static let handledKey = "NetworkDebugURLProtocolHandledKey"
    private static let session = URLSession(configuration: .default)

    private var task: URLSessionDataTask?
    private var startTime: CFAbsoluteTime = 0
    private var receivedData = Data()

    public override class func canInit(with request: URLRequest) -> Bool {
        if URLProtocol.property(forKey: handledKey, in: request) != nil { return false }
        guard let scheme = request.url?.scheme?.lowercased() else { return false }
        return scheme == "http" || scheme == "https"
    }

    public override class func canonicalRequest(for request: URLRequest) -> URLRequest { request }

    public override func startLoading() {
        startTime = CFAbsoluteTimeGetCurrent()
        receivedData = Data()

        let requestID = UUID().uuidString
        var newRequest = request
        URLProtocol.setProperty(true, forKey: Self.handledKey, in: &newRequest)

        let headers = newRequest.allHTTPHeaderFields ?? [:]
        let body = newRequest.httpBody

        APIAnalytics.shared.track(APIEvent(
            phase: .request,
            requestID: requestID,
            url: newRequest.url?.absoluteString ?? "nil",
            method: newRequest.httpMethod ?? "nil",
            headers: headers,
            requestBody: body
        ))

        task = Self.session.dataTask(with: newRequest) { [weak self] data, response, error in
            guard let self else { return }
            let durationMs = Int((CFAbsoluteTimeGetCurrent() - self.startTime) * 1000.0)

            if let error = error {
                APIAnalytics.shared.track(APIEvent(
                    phase: .failure,
                    requestID: requestID,
                    url: newRequest.url?.absoluteString ?? "nil",
                    method: newRequest.httpMethod ?? "nil",
                    durationMs: durationMs,
                    headers: headers,
                    requestBody: body,
                    responseBody: data,
                    error: error
                ))
                self.client?.urlProtocol(self, didFailWithError: error)
                return
            }

            if let response = response {
                self.client?.urlProtocol(self, didReceive: response, cacheStoragePolicy: .notAllowed)
            }

            let responseBody = data ?? Data()
            if !responseBody.isEmpty {
                self.client?.urlProtocol(self, didLoad: responseBody)
            }

            let status = (response as? HTTPURLResponse)?.statusCode

            APIAnalytics.shared.track(APIEvent(
                phase: .response,
                requestID: requestID,
                url: newRequest.url?.absoluteString ?? "nil",
                method: newRequest.httpMethod ?? "nil",
                statusCode: status,
                durationMs: durationMs,
                headers: headers,
                requestBody: body,
                responseBody: responseBody
            ))

            self.client?.urlProtocolDidFinishLoading(self)
        }

        task?.resume()
    }

    public override func stopLoading() {
        task?.cancel()
        task = nil
    }
}

public enum AnalyticsDebugInstaller {
    public static func installNetworkDebugging(into configuration: URLSessionConfiguration) {
        var protocols = configuration.protocolClasses ?? []
        if protocols.contains(where: { $0 == NetworkDebugURLProtocol.self }) { return }
        protocols.insert(NetworkDebugURLProtocol.self, at: 0)
        configuration.protocolClasses = protocols
    }

    public static func enableGlobalUncaughtExceptionLogging() {
        NSSetUncaughtExceptionHandler { exception in
            AnalyticsDebug.shared.log(.error, "Uncaught exception", metadata: [
                "name": exception.name.rawValue,
                "reason": exception.reason,
                "callStack": exception.callStackSymbols
            ])
        }
    }
